const data = $input.first().json;
const candidates = data.candidates || [];
let resultText = '';
if (candidates.length > 0) {
  const parts = candidates[0].content?.parts || [];
  for (const part of parts) {
    if (part.text) resultText += part.text;
  }
}
if (resultText.trim()) {
  let clean = resultText.trim();
  if (clean.startsWith('"') && clean.endsWith('"')) clean = clean.slice(1, -1);
  if (clean.startsWith('```') && clean.endsWith('```')) clean = clean.replace(/^```\w*\n?/, '').replace(/\n?```$/, '').trim();
  return [{ json: { success: true, enhanced: clean } }];
}
return [{ json: { success: false, error: 'Could not enhance prompt', enhanced: $input.first().json.body?.prompt || '' } }];

const body = $input.first().json.body || {};
const prompt = body.prompt || '';
const refBase64 = body.refImageBase64 || null;
const refMime = body.refImageMime || null;

const parts = [];
if (refBase64 && refMime) {
  parts.push({ inlineData: { mimeType: refMime, data: refBase64 } });
}
parts.push({ text: 'You are an expert image prompt editor. You will receive:
1. A reference image of a person/subject
2. An existing image generation prompt

Your task is to MODIFY the existing prompt so that the generated image will MATCH the person/subject in the reference image.

RULES:
- Carefully analyze the reference image: gender, ethnicity, approximate age, hair style/color, facial features, body type, skin tone.
- Replace ANY conflicting subject descriptions in the prompt with ones that match the reference image.
- Keep the overall scene, composition, lighting, artistic style, background, and mood EXACTLY the same.
- Keep ALL text overlay instructions unchanged.
- Keep the same language as the original prompt.
- Output ONLY the modified prompt text, nothing else.

--- EXISTING PROMPT ---
' + prompt + '
--- END PROMPT ---

Please output the modified prompt:' });

const requestBody = {
  contents: [{ parts }],
  generationConfig: { temperature: 0.3, maxOutputTokens: 4096 }
};

return [{ json: { requestBody } }];

const data = $input.first().json;
const candidates = data.candidates || [];
let resultText = '';
if (candidates.length > 0) {
  const parts = candidates[0].content?.parts || [];
  for (const part of parts) {
