  if (clean.startsWith('"') && clean.endsWith('"')) clean = clean.slice(1, -1);
  if (clean.startsWith('```') && clean.endsWith('```')) clean = clean.replace(/^```\w*\n?/, '').replace(/\n?```$/, '').trim();
  return [{ json: { success: true, adaptedPrompt: clean } }];
}
return [{ json: { success: false, error: 'Could not analyze reference image' } }];

const body = $input.first().json.body || {};
const refBase64 = body.refImageBase64 || null;
const refMime = body.refImageMime || null;

const parts = [];
if (refBase64 && refMime) {
  parts.push({ inlineData: { mimeType: refMime, data: refBase64 } });
}
parts.push({ text: 'Analyze this image in detail and write a comprehensive image generation prompt in English that would recreate this image. Include details about: subject, pose, expression, clothing, setting, lighting, colors, camera angle, mood, and artistic style. Output ONLY the prompt text, no explanation or labels.' });

const requestBody = {
  contents: [{ parts }],
  generationConfig: { temperature: 0.7, maxOutputTokens: 2048 }
};

return [{ json: { requestBody } }];

const data = $input.first().json;

// Check for HTTP/Gemini error first
if (data.error) {
  return [{ json: { success: false, error: 'Gemini API: ' + (data.error.message || JSON.stringify(data.error)) } }];
}

const candidates = data.candidates || [];
if (candidates.length > 0) {
  const parts = candidates[0].content?.parts || [];
  let resultText = '';
  for (const part of parts) {
    if (part.text) resultText += part.text;
  }
  if (resultText.trim()) {
    let clean = resultText.trim();
    if (clean.startsWith('"') && clean.endsWith('"')) clean = clean.slice(1, -1);
    if (clean.startsWith('```') && clean.endsWith('```')) clean = clean.replace(/^```\w*\n?/, '').replace(/\n?```$/, '').trim();
    return [{ json: { success: true, description: clean } }];
  }
}

if (data.promptFeedback?.blockReason) {
  return [{ json: { success: false, error: 'Prompt bị chặn: ' + data.promptFeedback.blockReason } }];
}

// Return raw response for debugging
return [{ json: { success: false, error: 'Could not describe image', debug: JSON.stringify(data).substring(0, 500) } }];

const body = $input.first().json.body || {};
const prompt = body.prompt || 'a beautiful landscape';
const aspectRatio = body.aspect_ratio || '1:1';
const quality = body.quality || '1k';
const refBase64 = body.refImageBase64 || null;
const refMime = body.refImageMime || null;

const arMap = {
  '1:1': 'square format (1:1 aspect ratio)',
  '9:16': 'vertical portrait format (9:16 aspect ratio, taller than wide)',
  '16:9': 'horizontal landscape format (16:9 aspect ratio, wider than tall)',
  '4:3': '4:3 aspect ratio format',
  '3:4': 'portrait 3:4 aspect ratio format',
  '3:2': '3:2 aspect ratio format',
  '2:3': 'portrait 2:3 aspect ratio format'
};
const arDesc = arMap[aspectRatio] || aspectRatio + ' aspect ratio';

const parts = [];
if (refBase64 && refMime) {
  parts.push({ inlineData: { mimeType: refMime, data: refBase64 } });
  parts.push({ text: `Generate an image in ${arDesc}. Use the provided reference image as visual guidance.\n\n${prompt}` });
} else {
  parts.push({ text: `Generate an image in ${arDesc}.\n\n${prompt}` });
}

const requestBody = {
  contents: [{ parts }],
  generationConfig: {
    responseModalities: ['IMAGE', 'TEXT'],
    temperature: 1,
    maxOutputTokens: 8192
  }
};

return [{ json: { requestBody, prompt, aspectRatio, quality } }];

const data = $input.first().json;
if (data.error) {
  return [{ json: { success: false, error: data.error.message || 'Gemini API error', code: data.error.code || 500 } }];
}
const candidates = data.candidates || [];
if (candidates.length > 0) {
  const parts = candidates[0].content?.parts || [];
  for (const part of parts) {
    if (part.inlineData) {
      const mimeType = part.inlineData.mimeType || 'image/png';
      const base64Data = part.inlineData.data;
      return [{ json: { success: true, imageUrl: `data:${mimeType};base64,${base64Data}`, mimeType, size: Math.round(base64Data.length / 1024) + 'KB' } }];
    }
  }
  for (const part of parts) {
    if (part.text) {
      return [{ json: { success: false, error: 'Gemini chỉ trả text, không tạo được ảnh. Thử prompt khác.', text: part.text.substring(0, 500) } }];
    }
  }
}
if (data.promptFeedback?.blockReason) {
  return [{ json: { success: false, error: 'Prompt bị chặn: ' + data.promptFeedback.blockReason } }];
}
return [{ json: { success: false, error: 'Không có ảnh trong response' } }];
